class Solution:
    def possibleBipartition(self, n: int, dislikes: List[List[int]]) -> bool:
        graph = [[] for _ in range(n + 1)]
        for u, v in dislikes:
            graph[u].append(v)
            graph[v].append(u)

        color = [0] * (n + 1)

        def dfs(node):
            for neighbor in graph[node]:
                if color[neighbor] == color[node]:
                    return False
                if color[neighbor] == 0:
                    color[neighbor] = 3 - color[node]
                    if not dfs(neighbor):
                        return False
            return True

        for i in range(1, n + 1):
            if color[i] == 0:
                color[i] = 1
                if not dfs(i):
                    return False
        return True
